 ('9369633f-0096-5b24-89db-c7d8845c3eef','5343483d-5bee-5da2-bd72-fc3c606155a7',1,$p$Sinónimos finos y su matiz (bekijken, staren, gluren…)$p$,$p$Sinónimos finos y su matiz (bekijken, staren, gluren…)$p$,'lesson',15),
 ('4f82b8f4-9749-5ee2-97b7-aa0eff617674','5343483d-5bee-5da2-bd72-fc3c606155a7',2,$p$Colocaciones (een besluit nemen, kritiek uiten, maatregelen treffen)$p$,$p$Colocaciones (een besluit nemen, kritiek uiten, maatregelen treffen)$p$,'lesson',15),
 ('5255e07b-37b7-5585-9b01-6ed0c66ce877','5343483d-5bee-5da2-bd72-fc3c606155a7',3,$p$Registros: formeel, neutraal, informeel$p$,$p$Registros: formeel, neutraal, informeel$p$,'lesson',15),
 ('4932baf2-3b22-57cf-8c1f-6688b24cdcfc','5343483d-5bee-5da2-bd72-fc3c606155a7',4,$p$Precisión: kennen/weten, liggen/leggen$p$,$p$Precisión: kennen/weten, liggen/leggen$p$,'lesson',15),
 ('e8de0737-16b7-59fb-9fdd-12f8c826963b','5343483d-5bee-5da2-bd72-fc3c606155a7',5,$p$🏁 Checkpoint Eenheid 25$p$,$p$Demuestra que eliges la palabra precisa a nivel C1 en neerlandés: distingues sinónimos finos y su connotación (bekijken/staren/gluren/turen, wonen/leven), dominas las colocaciones (een besluit nemen, kritiek uiten, maatregelen treffen), adaptas el registro (formeel/informeel: wagen/auto/kar, dineren/eten) y evitas errores de precisión (kennen vs weten, liggen vs leggen).$p$,'checkpoint',40)
