 ('5e49a7a9-3fa5-58b3-b2a9-614082fdf345','3a95a619-49ae-5185-b55b-4fca16d53c3d',1,$p$Concesivos: niettemin, desalniettemin, nochtans$p$,$p$Concesivos: niettemin, desalniettemin, nochtans$p$,'lesson',15),
 ('e02716ab-afee-52ab-9f74-c177d0f4294c','3a95a619-49ae-5185-b55b-4fca16d53c3d',2,$p$Causales y de refuerzo: aangezien, immers, temeer daar$p$,$p$Causales y de refuerzo: aangezien, immers, temeer daar$p$,'lesson',15),
 ('1473af68-e177-5932-8ee0-5d63d7efd1f6','3a95a619-49ae-5185-b55b-4fca16d53c3d',3,$p$Consecutivos y contraste: bijgevolg, derhalve, evenwel$p$,$p$Consecutivos y contraste: bijgevolg, derhalve, evenwel$p$,'lesson',15),
 ('6f7853a3-858e-5b9c-a42b-34d1aff60abf','3a95a619-49ae-5185-b55b-4fca16d53c3d',4,$p$Estructuras: niettegenstaande, weliswaar … maar, laat staan$p$,$p$Estructuras: niettegenstaande, weliswaar … maar, laat staan$p$,'lesson',15),
 ('2fecb1cc-387d-58dd-8e08-116c80cb1ee3','3a95a619-49ae-5185-b55b-4fca16d53c3d',5,$p$🏁 Checkpoint Eenheid 26$p$,$p$Demuestra que argumentas a nivel C1 en neerlandés: usas conectores concesivos (niettemin, desalniettemin, nochtans), causales (aangezien, immers, temeer daar), consecutivos (bijgevolg, derhalve), la preposición «niettegenstaande» + segundo caso y estructuras de contraste (weliswaar … maar, laat staan), respetando la V2 tras el conector en primera posición.$p$,'checkpoint',40)
