('82bd9878-aea5-571b-a748-74a37bc6ef27'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'C1','reading','multiple_choice',$p$Al anteponer el objeto al inicio de la oración, el verbo conjugado queda en segunda posición (V2). Elige la frase correcta:$p$,$j${"options": ["Deze fout zou niemand hebben opgemerkt.", "Deze fout niemand zou hebben opgemerkt.", "Deze fout hebben zou niemand opgemerkt."]}$j$::jsonb,$j${"value": "Deze fout zou niemand hebben opgemerkt."}$j$::jsonb,0.84,ARRAY[$p$unidad27$p$, $p$vooropplaatsing_mc$p$, $p$reading$p$]),
('23251365-4a9b-5e12-882e-3e147f793369'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'C1','writing','cloze',$p$Completa con la fórmula enfática de dos palabras que contradice («sí que»): «Men beweert dat hij van niets weet, maar hij heeft het ___ ___ gemerkt.»$p$,$j${"text": "Men beweert dat hij van niets weet, maar hij heeft het ___ ___ gemerkt."}$j$::jsonb,$j${"value": "wel degelijk", "accepted": ["wel degelijk"]}$j$::jsonb,0.84,ARRAY[$p$unidad27$p$, $p$vooropplaatsing_weldegelijk_cloze$p$, $p$writing$p$]),
('7090aa07-d48c-5968-9443-be42ee2c6a7c'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'C1','writing','word_bank',$p$Ordena las fichas para formar (objeto antepuesto): «Van dit voorstel houd ik niet veel.»$p$,$j${"tiles": ["houd", "Van dit", "veel", "ik", "voorstel", "niet", "weinig"]}$j$::jsonb,$j${"value": "Van dit voorstel houd ik niet veel", "sequence": ["Van dit", "voorstel", "houd", "ik", "niet", "veel"]}$j$::jsonb,0.84,ARRAY[$p$unidad27$p$, $p$vooropplaatsing_word_bank$p$, $p$writing$p$]),
