 ('d86f376f-59aa-509a-989f-8518eec1fc67','20000000-0000-0000-0000-000000000006','C1',29,$p$Hipótesis y modalidad avanzada: conditionalis y suposición$p$,'#7D3C98','psychology_alt')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('ec996b98-efb8-5869-8738-e56ccc9cf574','d86f376f-59aa-509a-989f-8518eec1fc67',1,$p$Condiciones y deseos irreales (conditionalis)$p$,$p$Condiciones y deseos irreales (conditionalis)$p$,'lesson',15),
 ('5db65a3f-f801-58c1-aca9-6b6d1c9deda3','d86f376f-59aa-509a-989f-8518eec1fc67',2,$p$Suposición: zal wel, moet … zijn, schijnt te …$p$,$p$Suposición: zal wel, moet … zijn, schijnt te …$p$,'lesson',15),
 ('7a4797d1-ec12-5927-a20f-51528c531093','d86f376f-59aa-509a-989f-8518eec1fc67',3,$p$Estilo indirecto y modo optativo (moge, ware)$p$,$p$Estilo indirecto y modo optativo (moge, ware)$p$,'lesson',15),
 ('42d422ba-77a6-5745-802c-7c6559be6793','d86f376f-59aa-509a-989f-8518eec1fc67',4,$p$Comparación irreal: alsof + verleden tijd$p$,$p$Comparación irreal: alsof + verleden tijd$p$,'lesson',15),
 ('16756f5d-5de4-5a07-9eb1-470e35835324','d86f376f-59aa-509a-989f-8518eec1fc67',5,$p$🏁 Checkpoint Eenheid 29$p$,$p$Demuestra que manejas la modalidad a nivel C1 en neerlandés: formas condiciones irreales (Als ik tijd had, zou ik …; Als ik tijd had gehad, was ik …), expresas suposición (zal wel, moet … zijn, schijnt/blijkt te …), reproduces el estilo indirecto con el desplazamiento temporal, usas el modo optativo formal (moge, ware) y comparaciones irreales con «alsof» + pasado.$p$,'checkpoint',40)
